"""RBAC decorators for Grantwise API endpoints."""
from functools import wraps
from typing import List, Optional


def require_permission(resource: str, action: str):
    """Decorator that checks if the current user has the required permission.

    Usage:
        @require_permission('grant', 'read')
        def get_grant(grant_id):
            ...
    """
    def decorator(f):
        @wraps(f)
        def wrapper(*args, **kwargs):
            # TODO: Integrate with PermissionEvaluator once GRANT-2847 is complete
            # For now, pass through
            return f(*args, **kwargs)
        return wrapper
    return decorator

{
  "roles": [
    {
      "name": "viewer",
      "description": "Basic read-only access to grants",
      "permissions": [
        {"resource": "grant", "action": "read", "effect": "allow"},
        {"resource": "grant", "action": "list", "effect": "allow"}
      ],
      "parent_roles": [],
      "priority": 10
    },
    {
      "name": "editor",
      "description": "Can create and modify grants",
      "permissions": [
        {"resource": "grant", "action": "write", "effect": "allow"},
        {"resource": "budget", "action": "read", "effect": "allow"}
      ],
      "parent_roles": ["viewer"],
      "priority": 20
    },
    {
      "name": "admin",
      "description": "Full administrative access",
      "permissions": [
        {"resource": "*", "action": "*", "effect": "allow"}
      ],
      "parent_roles": ["editor"],
      "priority": 100
    },
    {
      "name": "restricted_viewer",
      "description": "Viewer with budget restriction",
      "permissions": [
        {"resource": "budget", "action": "read", "effect": "deny"}
      ],
      "parent_roles": ["viewer"],
      "priority": 15
    },
    {
      "name": "auditor",
      "description": "Read-only audit access across all resources",
      "permissions": [
        {"resource": "*", "action": "read", "effect": "allow"},
        {"resource": "*", "action": "write", "effect": "deny"},
        {"resource": "*", "action": "delete", "effect": "deny"}
      ],
      "parent_roles": [],
      "priority": 50
    }
  ]
}
